mapper.select:
select total_point 
from member_point_tbl
where member_id = #{memberId}

SELECT pointNo, memberId, pointChange, pointType, pointReason, createdDate FROM (
SELECT POINT_NO AS pointNo, MEMBER_ID AS memberId, POINT_CHANGE AS pointChange, POINT_TYPE AS pointType, POINT_REASON AS pointReason, TO_CHAR(CREATED_DATE, 'YYYY-MM-DD') AS createdDate, CREATED_DATE AS orderDate FROM POINT_TBL WHERE MEMBER_ID = #{memberId}
UNION ALL
SELECT CONTRIBUTION_NO AS pointNo, MEMBER_ID AS memberId, -CONTRIBUTED_POINT AS pointChange, 'USE' AS pointType, '나무 물주기' AS pointReason, TO_CHAR(CONTRIBUTED_AT, 'YYYY-MM-DD') AS createdDate, CONTRIBUTED_AT AS orderDate FROM REGION_CONTRIBUTION_TBL WHERE MEMBER_ID = #{memberId}
UNION ALL
SELECT D.DONATION_NO AS pointNo, D.MEMBER_ID AS memberId, -D.DONATION_POINT AS pointChange, 'DONATION' AS pointType, G.GROUP_NAME || '에 ' || D.DONATION_POINT || 'P 기부' AS pointReason, TO_CHAR(D.DONATION_DATE, 'YYYY-MM-DD') AS createdDate, D.DONATION_DATE AS orderDate FROM POINT_DONATION D JOIN DONATION_GROUP G ON D.GROUP_ID = G.GROUP_ID WHERE D.MEMBER_ID = #{memberId} AND D.DONATION_POINT > 0 ) ORDER BY orderDate DESC, pointNo DESC
